mapper.select:
SELECT A.`id`, A.`user_id` userId,D.group_id groupId ,A.`channel_id` channelId,A.`app_id` appId ,B.nickname,B.email,B.account,C.`name` tenantName,E.`name` groupName ,IF(LENGTH(B.phone) = 11,CONCAT(SUBSTRING(B.phone, 1, 3), '****', SUBSTRING(B.phone, 8, 4)), B.phone) AS phone ,A.create_time createTime FROM `md_user_channel_related` A INNER JOIN `md_user` B ON A.`user_id`=B.id INNER JOIN `md_tenant` C ON A.`tenant_id`=C.id left join `md_user_channel` D ON A.channel_id=D.id LEFT JOIN `md_user_channel_group` E ON D.group_id=E.id WHERE A.app_id = #{appId} AND A.channel_id = #{channelId}
AND (B.nickname like concat('%',#{name},'%') or B.phone like concat('%',#{name},'%') or B.email like concat('%',#{name},'%') or B.account like concat('%',#{name},'%'))
order by createTime desc
